import { useState} from 'react';
import { setIcon } from './utils.js';
import { ICONS } from './Icons.js';
import classNames from 'classnames';

const STANDARD_ICON_ID = 2;


const ICON = ({source, label, onClick}) => {
    return (
        <div className='Icon'>
            <img src={source} alt={label} onClick={onClick} id='tree'/>
        </div>
    )
}

const ICONS_List = ({ICONS, visible}) => {
    // visible / hidden
    return (
        <div className={classNames(ICONS_List, visible && 'icons-list visible')}>
            {
              ICONS.map((icon) => (
                 <ICON {...icon} key={icon.id}/>
                ))
            }
        </div>
    )
}


// Build Skeleton avatar picker compononent
// current acrtive avatar
// popover + styling
// click outside to close
// select avatar
//any remaining animations

const IconPicker = () => {

    const [selectedIcon, setSelectedIcon] = useState(STANDARD_ICON_ID);
    const currentActiveIcon = ICONS.find(icon => icon.id === selectedIcon);
    const [showIconList, setShowIconListVisibility] = useState(false);

    return (
        <div className="icon-picker">
            <ICON onClick={() => {
                setShowIconListVisibility((showIconList) => !showIconList);
            } } {...currentActiveIcon}/>
            <ICONS_List visible={showIconList} ICONS={ICONS}/>
        </div>
    )
};

export default IconPicker;
